 | founded = {{ill|940|ja|940th year }} ({{ill|Tenkei|ja|天慶}} 3)
 | other names = Yuki Myōjin
 | festival = {{ill|October 22|ja|10月22日}} ({{ill|Kurama Fire Festival|ja|鞍馬の火祭}})
